import { describe, it, expect } from 'vitest';
import { buleyeanWeight } from '@a0n/buleyean-kernel';
import {
  rejectionWeightedFold,
  type SurvivingCandidate,
  type RejectionPoint,
} from '../src/buleyean-rejection-weights';

describe('rejectionWeightedFold', () => {
  it('collapses to plain Buleyean weights when there are no rejections', () => {
    const survivors: SurvivingCandidate[] = [
      { sigma: 1.0, rank: 0 },
      { sigma: 1.5, rank: 1 },
      { sigma: 2.0, rank: 2 },
    ];
    const rejected: RejectionPoint[] = [];

    const result = rejectionWeightedFold({ survivors, rejected });

    // R=3, buleyeanWeight(R, v) = R - min(v, R) + 1
    // For rank 0 → 4, rank 1 → 3, rank 2 → 2
    expect(result.weights).toEqual([
      buleyeanWeight(3, 0),
      buleyeanWeight(3, 1),
      buleyeanWeight(3, 2),
    ]);
    expect(result.weights).toEqual([4, 3, 2]);
    // No rejections → distances are Infinity
    for (const d of result.proximityDistances) {
      expect(d).toBe(Infinity);
    }
  });

  it('down-weights a survivor that sits exactly on a rejection sigma', () => {
    const survivors: SurvivingCandidate[] = [
      { sigma: 2, rank: 0 },
      { sigma: 3, rank: 1 },
    ];
    const rejected: RejectionPoint[] = [{ sigma: 2 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 0.5 });

    // R=2. buleyeanWeight(R, v) = R - v + 1.
    // survivor 0: d=0, p=1, w_rank = buleyeanWeight(2, 0) = 3,
    //   w_aug = 3 * (1 - 0.5*1) = 1.5
    // survivor 1: d=1, p=0.5, w_rank = buleyeanWeight(2, 1) = 2,
    //   w_aug = 2 * (1 - 0.5*0.5) = 1.5
    expect(result.weights[0]).toBeCloseTo(1.5, 6);
    expect(result.weights[1]).toBeCloseTo(1.5, 6);
    // Both attenuated; the relative attenuation hits survivor 0 (50% drop)
    // harder than survivor 1 (25% drop). Verify via pre-floor ratio.
    const wRank0 = buleyeanWeight(2, 0); // 3
    const wRank1 = buleyeanWeight(2, 1); // 2
    const augRaw0 = wRank0 * (1 - 0.5 * 1.0); // 1.5
    const augRaw1 = wRank1 * (1 - 0.5 * 0.5); // 1.5
    expect(augRaw0 / wRank0).toBeLessThan(augRaw1 / wRank1);
    // Diagnostic distances populated correctly.
    expect(result.proximityDistances).toEqual([0, 1]);
  });

  it('has minimal effect when the rejection is far from the survivor', () => {
    const survivors: SurvivingCandidate[] = [{ sigma: 2, rank: 0 }];
    const rejected: RejectionPoint[] = [{ sigma: 20 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 0.5 });

    const wRank = buleyeanWeight(1, 0); // R=1, rank=0 → 2
    const d = 18;
    const p = 1 / (1 + d);
    const expectedAug = wRank * (1 - 0.5 * p);
    const expectedWeight = Math.max(1, expectedAug);

    expect(result.weights[0]).toBeCloseTo(expectedWeight, 10);
    // Rank-only baseline weight = buleyeanWeight(1, 0) = 2; far-rejection
    // attenuation should leave the result within 5% of that baseline.
    expect(Math.abs(result.weights[0] - 2)).toBeLessThan(0.1);
    expect(result.proximityDistances[0]).toBe(18);
  });

  it('alpha=0 ignores rejections entirely', () => {
    const survivors: SurvivingCandidate[] = [
      { sigma: 2, rank: 0 },
      { sigma: 3, rank: 1 },
    ];
    const rejected: RejectionPoint[] = [{ sigma: 2 }];

    const withZero = rejectionWeightedFold({ survivors, rejected, alpha: 0 });
    const baseline = rejectionWeightedFold({ survivors, rejected: [] });

    expect(withZero.weights).toEqual(baseline.weights);
    expect(withZero.totalWeight).toBe(baseline.totalWeight);
  });

  it('alpha=1 maxes out attenuation', () => {
    const survivors: SurvivingCandidate[] = [
      { sigma: 2, rank: 0 },
      { sigma: 3, rank: 1 },
    ];
    const rejected: RejectionPoint[] = [{ sigma: 2 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 1 });

    // R=2. buleyeanWeight(R, v) = R - v + 1.
    // survivor 0: d=0, p=1, w_rank=3, w_aug = 3 * (1 - 1*1) = 0 → floor 1
    expect(result.weights[0]).toBe(1);

    // survivor 1: d=1, p=0.5, w_rank=2, w_aug = 2 * (1 - 1*0.5) = 1 → floor 1 (already at 1)
    expect(result.weights[1]).toBe(1);

    // Verify the underlying math (pre-floor) is what we documented.
    const wRank0 = buleyeanWeight(2, 0);
    const wRank1 = buleyeanWeight(2, 1);
    expect(wRank0 * (1 - 1 * 1.0)).toBe(0);
    expect(wRank1 * (1 - 1 * 0.5)).toBe(1);
  });

  it('floors at 1 to preserve buleyean-positivity (no candidate fully silenced)', () => {
    const survivors: SurvivingCandidate[] = [{ sigma: 5, rank: 0 }];
    const rejected: RejectionPoint[] = [{ sigma: 5 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 1 });

    // d=0, p=1, w_rank = buleyeanWeight(1, 0) = 1, w_aug = 1 * 0 = 0 → floor 1
    expect(result.weights[0]).toBe(1);
    expect(result.weights[0]).toBeGreaterThan(0);
  });

  it('throws on invalid inputs', () => {
    // empty survivors
    expect(() =>
      rejectionWeightedFold({ survivors: [], rejected: [] }),
    ).toThrow(RangeError);

    // alpha < 0
    expect(() =>
      rejectionWeightedFold({
        survivors: [{ sigma: 1, rank: 0 }],
        rejected: [],
        alpha: -0.1,
      }),
    ).toThrow(RangeError);

    // alpha > 1
    expect(() =>
      rejectionWeightedFold({
        survivors: [{ sigma: 1, rank: 0 }],
        rejected: [],
        alpha: 1.5,
      }),
    ).toThrow(RangeError);

    // non-numeric alpha
    expect(() =>
      rejectionWeightedFold({
        survivors: [{ sigma: 1, rank: 0 }],
        rejected: [],
        alpha: NaN,
      }),
    ).toThrow(TypeError);

    expect(() =>
      rejectionWeightedFold({
        survivors: [{ sigma: 1, rank: 0 }],
        rejected: [],
        // @ts-expect-error — testing runtime guard against bad type
        alpha: 'half',
      }),
    ).toThrow(TypeError);
  });

  it('takes the minimum sigma-distance across multiple rejections', () => {
    const survivors: SurvivingCandidate[] = [{ sigma: 3, rank: 0 }];
    const rejected: RejectionPoint[] = [{ sigma: 2 }, { sigma: 10 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 0.5 });

    // d = min(|3-2|, |3-10|) = min(1, 7) = 1
    expect(result.proximityDistances[0]).toBe(1);

    const wRank = buleyeanWeight(1, 0); // 1
    const p = 1 / (1 + 1); // 0.5
    const expectedAug = wRank * (1 - 0.5 * p); // 1 * 0.75 = 0.75 → floored to 1
    expect(result.weights[0]).toBe(Math.max(1, expectedAug));
  });

  it('totalWeight equals the sum of weights', () => {
    const survivors: SurvivingCandidate[] = [
      { sigma: 1, rank: 0 },
      { sigma: 2, rank: 1 },
      { sigma: 3, rank: 2 },
      { sigma: 4, rank: 3 },
    ];
    const rejected: RejectionPoint[] = [{ sigma: 2.5 }];

    const result = rejectionWeightedFold({ survivors, rejected, alpha: 0.5 });

    const sum = result.weights.reduce((a, b) => a + b, 0);
    expect(result.totalWeight).toBeCloseTo(sum, 12);
  });
});
